always_ff @(posedge clk125) begin
  nrst <= ~key_s[0];  // external reset
end

assign LED[6] = ~nrst;

// buttons =====================================================================

delay #(
    .LENGTH( 2 ),
    .WIDTH( 6 )
) sw_SYNC_ATTR (
    .clk( clk125 ),
    .nrst( 1'b1 ),
    .ena( 1'b1 ),
